  const queueLobbyAction = (actionLabel: string, fn: () => boolean): void => {
    pendingAction = actionLabel;
    syncLobbyStatus();
    syncActionControls();
    const sent = fn();
    if (!sent) {
      pendingAction = null;
      syncLobbyStatus();
      syncActionControls();
      return;
