import type {
  Action,
  GameState,
  GridPosition,
  ServerMessage,
  DamageMode,
  PhalanxTurnResult,
} from '@phalanxduel/shared';

export type Screen = 'lobby' | 'waiting' | 'game' | 'gameOver' | 'auth';

export type HealthColor = 'green' | 'yellow' | 'red';

export interface ServerHealth {
  color: HealthColor;
  label: string;
  hint: string | null;
}

export interface AuthUser {
  id: string;
  gamertag: string;
  suffix: number | null;
  email: string;
  elo: number;
  favoriteSuit?: 'spades' | 'hearts' | 'diamonds' | 'clubs' | null;
  tagline?: string | null;
  avatarIcon?: string | null;
}

export interface AppState {
  connectionState: 'CONNECTING' | 'OPEN' | 'DISCONNECTED';
  screen: Screen;
  user: AuthUser | null;
  matchId: string | null;
  playerId: string | null;
  playerIndex: number | null;
  playerName: string | null;
  gameState: GameState | null;
  selectedAttacker: GridPosition | null;
  selectedDeployCard: string | null; // cardId
  error: string | null;
  damageMode: DamageMode;
  startingLifepoints: number;
  serverHealth: ServerHealth | null;
  isSpectator: boolean;
  spectatorCount: number;
  showHelp: boolean;
  validActions: Action[];
}

export type Listener = (state: AppState) => void;

// --- Session storage helpers ---
const SESSION_KEY = 'phalanx_session';

export interface StoredSession {
  matchId: string;
  playerId: string;
  playerIndex: number;
  playerName: string;
}

function saveSession(session: StoredSession): void {
  sessionStorage.setItem(SESSION_KEY, JSON.stringify(session));
}

function loadSession(): StoredSession | null {
  try {
    const raw = sessionStorage.getItem(SESSION_KEY);
    if (!raw) return null;
    return JSON.parse(raw) as StoredSession;
  } catch {
    return null;
  }
}

function clearSession(): void {
  sessionStorage.removeItem(SESSION_KEY);
}

export function getSavedSession(): StoredSession | null {
  return loadSession();
}

let state: AppState = {
  connectionState: 'CONNECTING',
  screen: 'lobby',
  user: null,
  matchId: null,
  playerId: null,
  playerIndex: null,
  playerName: null,
  gameState: null,
  selectedAttacker: null,
  selectedDeployCard: null,
  error: null,
  damageMode: 'classic',
  startingLifepoints: 20,
  serverHealth: null,
  isSpectator: false,
  spectatorCount: 0,
  showHelp: false,
  validActions: [],
};

const listeners: Listener[] = [];

export function getState(): AppState {
  return state;
}

function setState(partial: Partial<AppState>): void {
  state = { ...state, ...partial };
  for (const listener of listeners) {
    listener(state);
  }
}

export function subscribe(listener: Listener): () => void {
  listeners.push(listener);
  return () => {
    const idx = listeners.indexOf(listener);
    if (idx !== -1) listeners.splice(idx, 1);
  };
}

// Side-channel for PizzazzEngine + NarrationProducer
export type TurnResultCallback = (result: PhalanxTurnResult) => void;
const turnResultCallbacks: TurnResultCallback[] = [];

export function onTurnResult(cb: TurnResultCallback): () => void {
  turnResultCallbacks.push(cb);
  return () => {
    const idx = turnResultCallbacks.indexOf(cb);
    if (idx !== -1) turnResultCallbacks.splice(idx, 1);
  };
}

export type AppMessage =
  | ServerMessage
  | { type: 'AUTH_SUCCESS'; user: AuthUser; token: string }
  | { type: 'CONNECTION_STATE'; state: AppState['connectionState']; error?: string };

export function dispatch(message: AppMessage): void {
  switch (message.type) {
    case 'AUTH_SUCCESS':
      setState({ user: message.user });
      break;

    case 'CONNECTION_STATE':
      setState({
        connectionState: message.state,
        ...(message.error ? { error: message.error } : {}),
      });
      if (message.state === 'OPEN') {
        setServerHealth({ color: 'green', label: 'Online', hint: 'Connected to game server' });
        clearError();
      } else if (message.state === 'CONNECTING') {
        setServerHealth({
          color: 'yellow',
          label: 'Reconnecting',
          hint: 'Attempting to restore the game session',
        });
      } else {
        setServerHealth({
          color: 'red',
          label: 'Offline',
          hint: message.error ?? 'Connection to game server lost',
        });
      }
      break;

    case 'matchCreated':
      vibrate(50);
      saveSession({
        matchId: message.matchId,
        playerId: message.playerId,
        playerIndex: message.playerIndex,
        playerName: state.playerName ?? '',
      });
      setState({
        screen: 'waiting',
        matchId: message.matchId,
        playerId: message.playerId,
        playerIndex: message.playerIndex,
        error: null,
      });
      break;

    case 'matchJoined':
      vibrate([30, 50, 30]);
      clearMatchParam();
      saveSession({
        matchId: message.matchId,
        playerId: message.playerId,
        playerIndex: message.playerIndex,
        playerName: state.playerName ?? '',
      });
      setState({
        matchId: message.matchId,
        playerId: message.playerId,
        playerIndex: message.playerIndex,
        error: null,
      });
      break;

    case 'spectatorJoined':
      vibrate(30);
      setState({
        screen: 'game',
        matchId: message.matchId,
        isSpectator: true,
        playerIndex: null,
        error: null,
      });
      break;

    case 'gameState': {
      const gs = message.result.postState;
      const myIdx = state.playerIndex;
      const isMyTurn = myIdx !== null && gs.activePlayerIndex === myIdx;

      // Haptic for turn start
      if (isMyTurn && state.gameState?.activePlayerIndex !== myIdx) {
        vibrate([100, 50, 100]);
      }

      for (const cb of turnResultCallbacks) cb(message.result);
      setState({
        screen: gs.phase === 'gameOver' ? 'gameOver' : 'game',
        gameState: gs,
        validActions: message.viewModel?.validActions ?? [],
        selectedAttacker: null,
        selectedDeployCard: null,
        error: null,
        spectatorCount: message.spectatorCount ?? 0,
      });
      break;
    }

    case 'actionError':
      vibrate([50, 50, 50]);
      setState({ error: message.error });
      break;

    case 'matchError':
      vibrate([50, 50, 50]);
      setState({ error: message.error });
      break;

    case 'opponentDisconnected':
      setState({ error: 'Opponent disconnected — waiting for reconnect...' });
      break;

    case 'opponentReconnected':
      vibrate(30);
      setState({ error: null });
      break;

    case 'authenticated':
      // Handled by connection layer, not state dispatch
      break;

    case 'auth_error':
      // Handled by connection layer, not state dispatch
      break;
  }
}

export function selectAttacker(pos: GridPosition): void {
  vibrate(10);
  setState({ selectedAttacker: pos, error: null });
}

export function selectDeployCard(cardId: string): void {
  vibrate(10);
  setState({ selectedDeployCard: cardId, error: null });
}

export function clearSelection(): void {
  vibrate(5);
  setState({ selectedAttacker: null, selectedDeployCard: null });
}

function vibrate(pattern: number | number[]): void {
  if (typeof navigator !== 'undefined' && navigator.vibrate) {
    try {
      navigator.vibrate(pattern);
    } catch {
      // Ignore vibration errors (e.g. security policy)
    }
  }
}

export function setUser(user: AuthUser | null): void {
  setState({ user });
}

export function setPlayerName(name: string): void {
  setState({ playerName: name });
}

export function setScreen(screen: Screen): void {
  setState({ screen });
}

export function setDamageMode(mode: DamageMode): void {
  setState({ damageMode: mode });
}

export function setStartingLifepoints(value: number): void {
  // Client-side guard; server schema is authoritative.
  const clamped = Math.max(1, Math.min(500, Math.trunc(value)));
  setState({ startingLifepoints: clamped });
}

export function setServerHealth(health: ServerHealth): void {
  setState({ serverHealth: health });
}

export function toggleHelp(): void {
  setState({ showHelp: !state.showHelp });
}

export function clearError(): void {
  setState({ error: null });
}

export function resetToLobby(): void {
  clearSession();
  clearMatchParam();
  setState({
    connectionState: 'CONNECTING',
    screen: 'lobby',
    matchId: null,
    playerId: null,
    playerIndex: null,
    playerName: null,
    gameState: null,
    selectedAttacker: null,
    error: null,
    damageMode: 'classic',
    startingLifepoints: 20,
    isSpectator: false,
    spectatorCount: 0,
    showHelp: false,
    validActions: [],
  });
}

function clearMatchParam(): void {
  const url = new URL(window.location.href);
  if (
    url.searchParams.has('match') ||
    url.searchParams.has('mode') ||
    url.searchParams.has('watch')
  ) {
    url.searchParams.delete('match');
    url.searchParams.delete('mode');
    url.searchParams.delete('watch');
    window.history.replaceState({}, '', url.toString());
  }
}

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { createConnection, type ConnectionLifecycleState } from '../src/connection';
import { setToken } from '../src/auth';

type WsListener = (event: unknown) => void;

class MockWebSocket {
  static OPEN = 1;
  static CLOSED = 3;
  static instances: MockWebSocket[] = [];

  url: string;
  readyState = MockWebSocket.OPEN;
  private listeners: Record<string, WsListener[]> = {};

  constructor(url: string) {
    this.url = url;
    MockWebSocket.instances.push(this);
  }

  addEventListener(event: string, cb: WsListener) {
    (this.listeners[event] ??= []).push(cb);
  }

  send = vi.fn();
  close = vi.fn((code?: number, reason?: string) => {
    this.readyState = MockWebSocket.CLOSED;
    this.fire('close', { code, reason });
  });

  fire(event: string, data?: unknown) {
    for (const cb of this.listeners[event] ?? []) {
      cb(data ?? {});
    }
  }
}

Object.defineProperty(MockWebSocket, 'OPEN', { value: 1 });
Object.defineProperty(MockWebSocket, 'CLOSED', { value: 3 });

describe('createConnection', () => {
  const sessionStore: Record<string, string> = {};
  let onMessage: ReturnType<
    typeof vi.fn<(message: import('@phalanxduel/shared').ServerMessage) => void>
  >;
  let onStateChange: ReturnType<typeof vi.fn<(state: ConnectionLifecycleState) => void>>;

  beforeEach(() => {
    vi.useFakeTimers();
    vi.spyOn(Math, 'random').mockReturnValue(0);
    MockWebSocket.instances = [];
    vi.stubGlobal('WebSocket', MockWebSocket);
    vi.stubGlobal('sessionStorage', {
      getItem: vi.fn((key: string) => sessionStore[key] ?? null),
      setItem: vi.fn((key: string, value: string) => {
        sessionStore[key] = value;
      }),
      removeItem: vi.fn((key: string) => {
        delete sessionStore[key];
      }),
    });
    onMessage = vi.fn();
    onStateChange = vi.fn();
    vi.clearAllMocks();
    setToken(null);
    for (const key of Object.keys(sessionStore)) delete sessionStore[key];
  });

  afterEach(() => {
    vi.restoreAllMocks();
    vi.useRealTimers();
    vi.unstubAllGlobals();
    setToken(null);
  });

  function lastWs(): MockWebSocket {
    return MockWebSocket.instances[MockWebSocket.instances.length - 1]!;
  }

  it('starts in CONNECTING and transitions to OPEN on socket open', () => {
    createConnection('ws://test:3001', onMessage, { onStateChange });
    expect(onStateChange).toHaveBeenCalledWith('CONNECTING');

    lastWs().fire('open');

    expect(onStateChange).toHaveBeenLastCalledWith('OPEN');
  });

  it('serializes reliable messages with msgId and telemetry', () => {
    const conn = createConnection('ws://test:3001', onMessage);
    const ws = lastWs();
    ws.fire('open');

    conn.send({
      type: 'createMatch',
      playerName: 'Alice',
      gameOptions: {
        damageMode: 'classic',
        startingLifepoints: 20,
        classicDeployment: true,
      },
    });

    const sent = JSON.parse(String(ws.send.mock.calls.at(-1)?.[0]));
    expect(sent).toMatchObject({
      type: 'createMatch',
      playerName: 'Alice',
      msgId: expect.any(String),
      telemetry: {
        originService: 'phx-client',
        reconnectAttempt: 0,
        sessionId: expect.any(String),
      },
    });
  });

  it('removes pending messages when the server ACKs them', () => {
    const conn = createConnection('ws://test:3001', onMessage);
    const ws = lastWs();
    ws.fire('open');

    conn.send({
      type: 'joinMatch',
      matchId: '3dff75bd-e19d-4ae6-99e4-bf6607ed58cb',
      playerName: 'Alice',
    });

    const outbound = JSON.parse(String(ws.send.mock.calls.at(-1)?.[0]));
    ws.send.mockClear();

    ws.fire('message', {
      data: JSON.stringify({ type: 'ack', ackedMsgId: outbound.msgId }),
    });

    ws.fire('close');
    vi.advanceTimersByTime(1000);
    lastWs().fire('open');

    expect(lastWs().send).not.toHaveBeenCalledWith(JSON.stringify(outbound));
  });

  it('flushes pending reliable messages after reconnect', () => {
    const conn = createConnection('ws://test:3001', onMessage);
    const ws = lastWs();
    ws.fire('open');

    conn.send({
      type: 'joinMatch',
      matchId: '3dff75bd-e19d-4ae6-99e4-bf6607ed58cb',
      playerName: 'Alice',
    });

    const outbound = JSON.parse(String(ws.send.mock.calls.at(-1)?.[0]));

    ws.fire('close');
    vi.advanceTimersByTime(1000);
    const reconnected = lastWs();
    reconnected.fire('open');

    const resent = reconnected.send.mock.calls
      .map((call) => JSON.parse(String(call[0])))
      .find((message) => message.type === 'joinMatch');
    expect(resent).toMatchObject({
      type: 'joinMatch',
      matchId: outbound.matchId,
      msgId: outbound.msgId,
    });
  });

  it('responds to server ping messages with pong', () => {
    createConnection('ws://test:3001', onMessage);
    const ws = lastWs();
    ws.fire('open');
    ws.send.mockClear();

    ws.fire('message', {
      data: JSON.stringify({
        type: 'ping',
        msgId: '20edcac1-2ca3-4d6a-9ca8-5b83a059d47d',
        timestamp: new Date().toISOString(),
      }),
    });

    const sent = JSON.parse(String(ws.send.mock.calls.at(-1)?.[0]));
    expect(sent).toMatchObject({
      type: 'pong',
      replyTo: '20edcac1-2ca3-4d6a-9ca8-5b83a059d47d',
    });
  });

  it('closes and reconnects when heartbeat times out', () => {
